const body = $json.body || $json;
for (const k of ['provider','input','requestedBy','reason']) if (!body[k]) throw new Error(`${k} required`);
return [{ json: {
  correlationId: `inv-void-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  requestedAt: new Date().toISOString(),
  provider: body.provider,
  requestedBy: body.requestedBy,
  reason: body.reason,
  input: body.input
}}];

// After form submission, $json contains the form field values keyed by fieldLabel.
const state = $node['Stamp correlation'].json;
const decision = ($json.decision || '').toLowerCase();
const approved = decision === 'approve';
const approver = $json.approver_email || 'form-unknown';
const note = $json.note || '';
return [{ json: {
  ...state,
  decision,
  approved,
  approver,
  note,
  decidedAt: new Date().toISOString()
}}];

const state = $node['Rehydrate after form'].json;
const statusCode = Number($json.statusCode ?? 0);
const ok = statusCode >= 200 && statusCode < 300;
return [{ json: { ...state, statusCode, ok, response: $json.body ?? $json } }];
